return items.map(item => {
  const b = item.json;
  const barrio = b.barrio?.name || '';
  const comments = Array.isArray(b.comments)
    ? b.comments.slice(0, 5).map((c, i) => `${i + 1}. ${c.text || c}`).join(' | ')
    : '';

  return {
    json: {
      content: `
Nombre: ${b.name || ''}
Barrio/Zona: ${barrio}
Categoría: ${b.category || ''}
Subcategoría: ${b.subcategory || ''}
Web registrada: ${b.has_website === true ? 'sí' : b.has_website === false ? 'no' : ''}
Reseñas: ${b.reviews || ''}
Gap: ${b.gap || ''}
Tipo: ${b.osm?.tags?.amenity || ''}
Cocina: ${b.osm?.tags?.cuisine || ''}
Dirección: ${b.osm?.tags?.['addr:street'] || ''}
Teléfono: ${b.osm?.tags?.phone || ''}
Horario: ${b.osm?.tags?.opening_hours || ''}
Delivery: ${b.osm?.tags?.delivery || ''}
Takeaway: ${b.osm?.tags?.takeaway || ''}
Comentarios: ${comments}
Score: ${b.score || ''}
`,
      metadata: {
        id: b._id,
        barrio,
        sector: b.category || '',
        subsector: b.subcategory || '',
        nombre: b.name || '',
        score: b.score,
      }
    }
  };
});
